const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

// Load your secret key from an environment variable or a secure storage
const secretKey = process.env.SECRET_KEY;

// Verify token middleware function
function verifyToken(req, res, next) {
    const authHeader = req.header('Authorization');
    if (!authHeader) return res.status(401).send({ error: 'No authorization header found' });

    const [type, token] = authHeader.split(' ');
    if (type !== 'Bearer') return res.status(401).send({ error: 'Invalid token type' });

    jwt.verify(token, secretKey, (err, decoded) => {
        if (err) return res.status(403).send({ error: 'Invalid token' });
        req.user = decoded;
        next();
    });
}

// API endpoint to validate access tokens
app.get('/validate-token', verifyToken, (req, res) => {
    res.send({ message: `Hello, ${req.user.username}!` });
});

const port = process.env.PORT || 3000;

app.listen(port, () => {
    console.log(`Server listening on port ${port}`);
});